            else:
                ctx_obj.echo(str(data[field]))
        else:
            ctx_obj.echo(f"Field '{field}' not found.", err=True, color="red")
            sys.exit(1)
        return

    if show_secret:
        ctx_obj.echo(
            "WARNING: Secret printed to stdout. Run: history -d <n> to remove from shell history.",
            err=True,
            color="yellow",
        )

    if ctx_obj.json_output:
