"""Health and readiness routes."""

from __future__ import annotations

from fastapi import APIRouter, Depends

from authsome import __version__
from authsome.auth import AuthService
from authsome.server.routes._deps import get_auth_service
from authsome.server.schemas import HealthResponse, ReadyResponse

router = APIRouter()


@router.get("/health", response_model=HealthResponse)
def health() -> HealthResponse:
    return HealthResponse(status="ok", version=__version__)


@router.get("/ready", response_model=ReadyResponse)
def ready(auth: AuthService = Depends(get_auth_service)) -> ReadyResponse:
    checks: dict[str, str] = {}
    issues: list[str] = []
    warnings: list[str] = []

    # 1. Config & Schema Version Check
    try:
        config = auth.app_store.get_config()
        checks["config"] = "ok"

        # Verify spec_version matches standard expected version (1)
        expected_spec_version = 1
        if getattr(config, "spec_version", None) != expected_spec_version:
            issues.append(
                f"config: spec_version mismatch (got {config.spec_version}, expected {expected_spec_version})"
            )
            checks["version_compatibility"] = "failed"
        else:
            checks["version_compatibility"] = "ok"
    except Exception as exc:
        checks["config"] = "failed"
        checks["version_compatibility"] = "failed"
        issues.append(f"config: {exc}")

    # 2. Profiles Count Check
    try:
        auth.list_profiles()
        checks["profiles"] = "ok"
    except Exception as exc:
        checks["profiles"] = "failed"
        issues.append(f"profiles: {exc}")

    # 3. Providers List Check
    try:
        auth.list_providers()
        checks["providers"] = "ok"
    except Exception as exc:
        checks["providers"] = "failed"
        issues.append(f"providers: {exc}")

    # 4. Connected Providers Check
    try:
        conn_list = auth.list_connections()
        checks["connections"] = "ok"
        connected_count = sum(1 for p in conn_list for c in p.get("connections", []) if c.get("status") == "connected")
        if connected_count == 0:
            warnings.append("no active provider connections found")
    except Exception as exc:
        checks["connections"] = "failed"
        issues.append(f"connections: {exc}")

    # 5. Vault Roundtrip & Store Integrity Check
    try:
        auth.vault.put("__ready_test__", "ok", profile=auth.identity)
        value = auth.vault.get("__ready_test__", profile=auth.identity)
        auth.vault.delete("__ready_test__", profile=auth.identity)

        if value != "ok":
            issues.append("vault: readiness roundtrip failed")
            checks["vault"] = "failed"
        else:
            checks["vault"] = "ok"

        if not auth.vault.check_integrity(profile=auth.identity):
            issues.append("vault: store failed integrity check")
            checks["integrity"] = "failed"
        else:
            checks["integrity"] = "ok"
    except Exception as exc:
        checks["vault"] = "failed"
        checks["integrity"] = "failed"
        issues.append(f"vault: {exc}")

    # TODO: Re-enable master.key permission checks once backend implementation stabilizes.
    # (Previous implementation alerted users if file was world-readable)

    except Exception as exc:
        if "file_permissions" not in checks:
            checks["file_permissions"] = "failed"
        checks["key_age"] = "failed"
        issues.append(f"file_checks: {exc}")

    status = "ready" if not issues else "not_ready"
    return ReadyResponse(status=status, checks=checks, issues=issues, warnings=warnings)


@router.get("/whoami")
def whoami(auth: AuthService = Depends(get_auth_service)) -> dict[str, str]:
    config = auth.app_store.get_config()
    enc_mode = config.encryption.mode if config.encryption else "local_key"
    if enc_mode == "local_key":
        enc_desc = f"Local Key ({auth.app_store.home / 'master.key'})"
    elif enc_mode == "keyring":
        enc_desc = "OS Keyring"
    else:
        enc_desc = enc_mode
    return {
        "version": __version__,
        "home": str(auth.app_store.home),
        "active_identity": auth.identity,
        "encryption_backend": enc_desc,
    }

"""Vault — the secure credential store.

The Vault is a generic encrypted key-value store. It owns:
- The master key (via a pluggable crypto backend)
- The SQLite storage backend
- Encryption and decryption of all stored values

The Vault knows nothing about credential types, token lifecycle, or OAuth.
All key schema decisions belong to the caller (AuthLayer).
"""

from __future__ import annotations

import builtins
from pathlib import Path
from typing import TYPE_CHECKING

from authsome.store.interfaces import AppStore, VaultStorage

if TYPE_CHECKING:
    from authsome.vault.crypto import VaultCrypto

_DEFAULT_PROFILE = "default"


class Vault:
    """
    Encrypted key-value store backed by SQLite.

    All values are encrypted at rest using AES-256-GCM. The master key is
    managed by the configured VaultCrypto backend (local file or OS keyring).

    The Vault is key-agnostic. Key schema is owned by AuthLayer.
    """

    def __init__(
        self,
        app_store: AppStore,
        crypto: VaultCrypto | None = None,
        crypto_mode: str = "local_key",
        master_key_path: Path | None = None,
    ) -> None:
        self._app_store = app_store
        self._crypto = crypto
        self._crypto_mode = crypto_mode
        self._master_key_path = master_key_path

    # ── Core KV interface ─────────────────────────────────────────────────

    @property
    def crypto(self) -> VaultCrypto:
        if self._crypto is None:
            from authsome.vault.crypto import create_crypto

            self._crypto = create_crypto(self._master_key_path, self._crypto_mode)
        return self._crypto

    # ── Core KV interface ─────────────────────────────────────────────────

    def get(self, key: str, *, profile: str = _DEFAULT_PROFILE) -> str | None:
        """Retrieve and decrypt a value. Returns None if key not found."""
        raw = self._storage(profile).get(key)
        if raw is None:
            return None
        return self.crypto.decrypt(raw)

    def put(self, key: str, value: str, *, profile: str = _DEFAULT_PROFILE) -> None:
        """Encrypt and store a value."""
        encrypted = self.crypto.encrypt(value)
        self._storage(profile).put(key, encrypted)

    def delete(self, key: str, *, profile: str = _DEFAULT_PROFILE) -> bool:
        """Delete a key. Returns True if the key existed."""
        return self._storage(profile).delete(key)

    def list(self, prefix: str = "", *, profile: str = _DEFAULT_PROFILE) -> builtins.list[str]:
        """List all keys matching a prefix."""
        return self._storage(profile).list_keys(prefix)

    def check_integrity(self, *, profile: str = _DEFAULT_PROFILE) -> bool:
        """Perform health check on underlying store."""
        return self._storage(profile).check_integrity()

    def close(self) -> None:
        """Close all open storage connections."""
        # Vault doesn't own the connections anymore, the AppStore does.
        pass

    def __enter__(self) -> Vault:
        return self

    def __exit__(self, *args: object) -> None:
        self.close()

    # ── Internal ──────────────────────────────────────────────────────────

    def _storage(self, profile: str) -> VaultStorage:
        return self._app_store.get_vault_storage(profile)

"""CLI Context management and decorators."""

import functools
import json as json_lib
import os
from pathlib import Path
from typing import Any

import click

from authsome import audit
from authsome.cli.client import AuthsomeApiClient
from authsome.cli.daemon_control import resolve_runtime_client
from authsome.proxy.runner import ProxyRunner


class CliRuntime:
    """CLI-local wiring around the daemon API client."""

    def __init__(self, client: AuthsomeApiClient) -> None:
        self.runtime_client = client
        self.home = Path(os.environ.get("AUTHSOME_HOME", str(Path.home() / ".authsome")))

    def doctor(self) -> dict[str, Any]:
        return self.runtime_client.doctor()

    def require_local_proxy(self) -> ProxyRunner:
        return ProxyRunner(client=self.runtime_client)


class ContextObj:
    """Context object passed to all commands."""

    def __init__(self, json_output: bool, quiet: bool, no_color: bool):
        self.json_output = json_output
        self.quiet = quiet
        self.no_color = no_color
