        self._key_file.parent.mkdir(parents=True, exist_ok=True)
        key_data = {
            "version": 1,
            "key": base64.b64encode(master_key).decode("ascii"),
            "algorithm": "AES-256-GCM",
            "note": "Local master key for authsome. Protect this file.",
        }
